esqlQuery.esql:
TS metrics-redisreceiver.otel-*
| WHERE redis.keys.evicted IS NOT NULL
// Counter: use INCREASE to get evictions over the time window
| STATS evicted = SUM(INCREASE(redis.keys.evicted))
  BY server.address, server.port
// Alert when evictions exceed threshold (adjust based on workload)
// Sudden spikes indicate memory pressure; sustained evictions may be normal for cache workloads
| WHERE evicted > 100
| SORT evicted DESC
